-- Ken's Hardened V2 Fix

local b64_0xIIlIll = {}
local char_0xlIlIl1='ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789+/'
for i_0xl1Illl=1,#char_0xlIlIl1 do b64_0xIIlIll[char_0xlIlIl1:sub(i_0xl1Illl,i_0xl1Illl)] = i_0xl1Illl - 1 end

function b64_0xIIlIll.dec_0x1lIlll(d_0x1lIlll)
    d_0x1lIlll = string.gsub(d_0x1lIlll, '[^'..char_0xlIlIl1..'=]', '')
    local r_0x1llIll = {}
    for i_0xl1Illl=1, #d_0x1lIlll, 4 do
        local c_0xlIl11l = b64_0xIIlIll[d_0x1lIlll:sub(i_0xl1Illl,i_0xl1Illl)] or 0
        local c_0x1IlIlI = b64_0xIIlIll[d_0x1lIlll:sub(i_0xl1Illl+1,i_0xl1Illl+1)] or 0
        local c_0xI1Il1I, c_0xIIIII1 = 0, 0
        local has3 = true
        local has4 = true
        local ch3 = d_0x1lIlll:sub(i_0xl1Illl+2,i_0xl1Illl+2)
        if ch3 == "=" then has3 = false else c_0xI1Il1I = b64_0xIIlIll[ch3] or 0 end
        local ch4 = d_0x1lIlll:sub(i_0xl1Illl+3,i_0xl1Illl+3)
        if ch4 == "=" then has4 = false else c_0xIIIII1 = b64_0xIIlIll[ch4] or 0 end
        local b_0xlIII1I = c_0xlIl11l * (2^18) + c_0x1IlIlI * (2^12) + c_0xI1Il1I * (2^6) + c_0xIIIII1
        local b_0xIlIIll = math.floor(b_0xlIII1I / (2^16)) % (2^8)
        local b_0xllIllI = math.floor(b_0xlIII1I / (2^8)) % (2^8)
        local b_0xlIIlIl = b_0xlIII1I % (2^8)
        table.insert(r_0x1llIll, string.char(b_0xIlIIll))
        if has3 then table.insert(r_0x1llIll, string.char(b_0xllIllI)) end
        if has4 then table.insert(r_0x1llIll, string.char(b_0xlIIlIl)) end
    end
    return table.concat(r_0x1llIll)
end


local function bxor_0xIllll1(a_0x11llll,b_0xlllllI)
    if bit32 then return bit32.bxor(a_0x11llll,b_0xlllllI) end
    local r_0xlII1lI = 0
    for i_0xIlll1I = 0, 7 do
        local x_0x1IIlI1 = a_0x11llll % 2
        local y_0x1IIl1I = b_0xlllllI % 2
        if x_0x1IIlI1 ~= y_0x1IIl1I then r_0xlII1lI = r_0xlII1lI + (2^i_0xIlll1I) end
        a_0x11llll = math.floor(a_0x11llll / 2)
        b_0xlllllI = math.floor(b_0xlllllI / 2)
    end
    return r_0xlII1lI
end


local function bxor_str_0xIlllII(s_0xl11lII, k_0x1lIIlI)
    local r_0xI1IlII = {}
    for i_0xIIIl1I=1, #s_0xl11lII do
        local b_0xIllIIl = string.byte(s_0xl11lII, i_0xIIIl1I)
        local kb_0xIII1l1 = string.byte(k_0x1lIIlI, (i_0xIIIl1I-1) % #k_0x1lIIlI + 1)
        r_0xI1IlII[i_0xIIIl1I] = string.char(bxor_0xIllll1(b_0xIllIIl, kb_0xIII1l1))
    end
    return table.concat(r_0xI1IlII)
end


local function getkeys_0xI1Ill1()
    local seed = b64_0xIIlIll.dec_0x1lIlll("Q0FZMlMwdzQ=")
    local k1_enc = b64_0xIIlIll.dec_0x1lIlll("MTtgez94FUU=")
    local k2_enc = b64_0xIIlIll.dec_0x1lIlll("FCwYazRjP0c=")
    return bxor_str_0xIlllII(k1_enc, seed), bxor_str_0xIlllII(k2_enc, seed)
end


local function cff_0xIlIIlI(a_0x1Ill1l)
    local st_0x11Ill1 = 0
    local res_0x1lllIl = a_0x1Ill1l
    while true do
        if st_0x11Ill1 == 0 then
            res_0x1lllIl = res_0x1lllIl + 1
            st_0x11Ill1 = 1
        elseif st_0x11Ill1 == 1 then
            res_0x1lllIl = res_0x1lllIl * 2
            st_0x11Ill1 = 2
        elseif st_0x11Ill1 == 2 then
            res_0x1lllIl = res_0x1lllIl - 3
            st_0x11Ill1 = 3
        else
            break
        end
    end
    return res_0x1lllIl
end


local function chain_0xI1lllI(x) return x*2 end
local function chain_0xIIl11l(x) return chain_0xI1lllI(x)+1 end


local d_0xlIlI1I = {
  {op=255, val="", is_enc=true},
}
local pc_0xIl1III = 1
local stk_0xllI1II = {}
stk_0xllI1II._jmp = nil


local disp_0xlIlII1 = {
    [0] = function() end,
    [1] = function(s, v) table.insert(s, v) end,
    [2] = function(s, v) table.insert(s, _G[v]) end,
    [3] = function(s, v) local val=table.remove(s); _G[v]=val end,
    [4] = function(s, _) table.insert(s, {}) end,
    [5] = function(s, _) local val=table.remove(s); local key=table.remove(s); local t=table.remove(s); t[key]=val; table.insert(s, t) end,
    [16] = function(s) local b=tonumber(table.remove(s)) or 0; local a=tonumber(table.remove(s)) or 0; table.insert(s, a+b) end,
    [17] = function(s) local b=tonumber(table.remove(s)) or 0; local a=tonumber(table.remove(s)) or 0; table.insert(s, a-b) end,
    [18] = function(s) local b=tonumber(table.remove(s)) or 0; local a=tonumber(table.remove(s)) or 0; table.insert(s, a*b) end,
    [19] = function(s) local b=tonumber(table.remove(s)) or 0; local a=tonumber(table.remove(s)) or 0; table.insert(s, a/b) end,
    [32] = function(s, n) 
        local args = {}
        for i=1,tonumber(n) do table.insert(args, 1, table.remove(s)) end
        local f = table.remove(s)
        if type(f) == "function" then
            local result = {f(unpack(args))}
            for _,v in ipairs(result) do table.insert(s, v) end
        else
            print("[LBI] Not a function: "..tostring(f))
        end
    end,
    [33] = function(s) return table.remove(s) end,
    [48] = function(s, offset) 
        local cond = table.remove(s)
        if not cond then 
            s._jmp = tonumber(offset)
        end
    end,
    [49] = function(s, offset)
        s._jmp = tonumber(offset)
    end,
    [255] = function(s, v)
        local fn, err = loadstring(v)
        if not fn then
            print("[LBI] Load error: "..tostring(err))
        else
            local ok, res = pcall(fn)
            if not ok then print("[LBI] Run error: "..tostring(res)) end
        end
    end
}



local k1, k2 = getkeys_0xI1Ill1()

local state_0xll1lI1 = 0
while true do
    if state_0xll1lI1 == 0 then  -- FETCH
        if pc_0xIl1III > #d_0xlIlI1I then break end
        local inst = d_0xlIlI1I[pc_0xIl1III]
        local opcode = inst.op
        local val = inst.val
        if inst.is_enc then
            local d = b64_0xIIlIll.dec_0x1lIlll(val)
            d = bxor_str_0xIlllII(d, k2)
            val = bxor_str_0xIlllII(d, k1)
        end
        stk_0xllI1II._jmp = nil
        pc_0xIl1III = pc_0xIl1III + 1
        cur_op_0xIIIIll = opcode
        cur_val_0xIl1lII = val
        state_0xll1lI1 = 1

    elseif state_0xll1lI1 == 1 then  -- EXECUTE
        local handler = disp_0xlIlII1[cur_op_0xIIIIll]
        if handler then
            handler(stk_0xllI1II, cur_val_0xIl1lII)
        end
        if stk_0xllI1II._jmp then
            pc_0xIl1III = pc_0xIl1III + stk_0xllI1II._jmp
        end
        state_0xll1lI1 = 0
    else
        break
    end
end
